<?php class Model_Alternativa{	private static $_instance;		public static function getInstance()	{		if(null == self::$_instance)		{			self::$_instance = new self;		}		return self::$_instance;	}	private function __construct(){}	public function getAlternativa($id)	{		return Model_Mapper_Alternativa::getInstance()->getAlternativa($id);	}		public function getAlternativas()	{		return Model_Mapper_Alternativa::getInstance()->getAlternativas();	}		public function getAlternativasOrdenIndicador()	{		return Model_Mapper_Alternativa::getInstance()->getAlternativasOrdenIndicador();	}		public function getIndicadorSiguiente($idAlternativa)	{		return Model_Mapper_Alternativa::getInstance()->getIndicadorSiguiente($idAlternativa);	}		public function getAlternativasByIndicador($idIndicador)	{		return Model_Mapper_Alternativa::getInstance()->getAlternativasByIndicador($idIndicador);	}		public function getConsejoByAlternativa($id)	{		return Model_Mapper_Alternativa::getInstance()->getConsejoByAlternativa($id);	}		public function getIndicador($id)	{		return Model_Mapper_Alternativa::getInstance()->getIndicador($id);	}		public function getPesoAlternativa($idAlternativa)	{		return Model_Mapper_Alternativa::getInstance()->getPesoAlternativa($idAlternativa);	}		public function getAlternativaByFicha($ficha)	{		return Model_Mapper_Alternativa::getInstance()->getAlternativaByFicha($ficha);	}		public function fichaExiste($ficha)	{		if( null != Model_Mapper_Alternativa::getAlternativaByFicha($ficha))		{			return true;		}		return false;	}		public function updateAlternativa($fila)	{		return Model_Mapper_Alternativa::getInstance()->updateAlternativa($fila);	}		public function insertAlternativa($fila)	{		return Model_Mapper_Alternativa::getInstance()->insertAlternativa($fila);	}}